4202                                    /*NSW=*/true, /*NUW=*/true))
4203       return R;
4204 
4205     if (Value *Res = foldDisjointOr(I.getOperand(0), I.getOperand(1)))
4206       return replaceInstUsesWith(I, Res);
4207 
4208     if (Value *Res = reassociateDisjointOr(I.getOperand(0), I.getOperand(1)))
4209       return replaceInstUsesWith(I, Res);
4210   }
4211 
4212   Value *X, *Y;
4213   const APInt *CV;
4214   if (match(&I, m_c_Or(m_OneUse(m_Xor(m_Value(X), m_APInt(CV))), m_Value(Y))) &&
4215       !CV->isAllOnes() && MaskedValueIsZero(Y, *CV, &I)) {
4216     // (X ^ C) | Y -> (X | Y) ^ C iff Y & C == 0
4217     // The check for a 'not' op is for efficiency (if Y is known zero --> ~X).
4218     Value *Or = Builder.CreateOr(X, Y);
4219     return BinaryOperator::CreateXor(Or, ConstantInt::get(Ty, *CV));
4220   }
4221 
4222   // If the operands have no common bits set:
4223   // or (mul X, Y), X --> add (mul X, Y), X --> mul X, (Y + 1)
4224   if (match(&I, m_c_DisjointOr(m_OneUse(m_Mul(m_Value(X), m_Value(Y))),
4225                                m_Deferred(X)))) {
4226     Value *IncrementY = Builder.CreateAdd(Y, ConstantInt::get(Ty, 1));
4227     return BinaryOperator::CreateMul(X, IncrementY);
4228   }
